const notas = [8, 5, 10, 7, 6];

for (let indice = 0; indice < notas.length; indice = indice + 1) {
  console.log('Nota atual:', notas[indice]);
}

const notas = [8, null, 10, undefined, 6];
let quantidadeValidas = 0;

for (let indice = 0; indice < notas.length; indice = indice + 1) {
  const notaAtual = notas[indice];

  if (notaAtual === null || notaAtual === undefined) {
    continue;
  }

  console.log('Nota válida:', notaAtual);
  quantidadeValidas = quantidadeValidas + 1;
}

console.log('Quantidade de notas válidas:', quantidadeValidas);

const notas = [8, 5, 10, 7, 6];
let encontrouNotaMaxima = false;

for (let indice = 0; indice < notas.length; indice = indice + 1) {
  const notaAtual = notas[indice];

  if (notaAtual === 10) {
    encontrouNotaMaxima = true;
    break;
  }
}

console.log('Encontrou nota máxima:', encontrouNotaMaxima);
